import{_ as t,o as l,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F02_營業現金流與獲利品質.md"}'),r={name:"審計報告庫/財務審計/3105_穩懋/20260503/F02_營業現金流與獲利品質.md"};function e(n,a,s,N,T,F){return l(),o("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f02-營業現金流與獲利品質-財務審計專家-審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務審計專家 審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務審計專家-審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？測算 CFO/Net Income 比值，判定獲利中「紙上富貴」的比例。</p></blockquote><h2 id="🎯-專家直斷-68-字" tabindex="-1">🎯 專家直斷（68 字） <a class="header-anchor" href="#🎯-專家直斷-68-字" aria-label="Permalink to &quot;🎯 專家直斷（68 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：穩懋 CFO/NI 比值達 516-1,537%，獲利含金量極高，但此結構性偏離主因鉅額折舊（NT$3.9-4.6B/年）壓縮帳面淨利，而非營運效率異常。FCF 連續三年為正，現金生產力穩健。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-131-字" tabindex="-1">📊 診斷評級（131 字） <a class="header-anchor" href="#📊-診斷評級-131-字" aria-label="Permalink to &quot;📊 診斷評級（131 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：CFO 連續三年高於 NT$4.27B：2023 年 NT$4.27B（FCF NT$1.52B）、2024 年 NT$4.90B（FCF NT$3.84B）、2025 年 NT$4.95B（FCF NT$10.07B）。折舊費用 NT$4.62B→NT$4.60B→NT$3.91B。CapEx 從 NT$3.11B 縮減至 NT$0.70B。期末現金 NT$10.3B→NT$5.4B→NT$7.1B。</li><li><strong>診斷見解</strong>：穩懋屬重資產晶圓代工，折舊非現金費用導致 NI 低估實際現金產出，CFO/NI 超標屬產業常態。惟 2024 NI 為負（-NT$530M）使比值失真，2025 回升至 516% 仍遠優於 100% 門檻。CapEx 縮減使 FCF 大幅擴張，但需確認是否犧牲長期競爭力。</li></ul><h2 id="🔍-答詢詳解-431-字" tabindex="-1">🔍 答詢詳解（431 字） <a class="header-anchor" href="#🔍-答詢詳解-431-字" aria-label="Permalink to &quot;🔍 答詢詳解（431 字）&quot;">​</a></h2><h3 id="獲利含金量-cfo-ni-比值深解" tabindex="-1">獲利含金量：CFO/NI 比值深解 <a class="header-anchor" href="#獲利含金量-cfo-ni-比值深解" aria-label="Permalink to &quot;獲利含金量：CFO/NI 比值深解&quot;">​</a></h3><ul><li><strong>核心重點</strong>：322.5% 三年加總比值（三年 CFO 合計 NT$14.12B ÷ 三年 NI 合計 NT$708M）。2023 年 CFO/NI 達 1,536.6%，主因 NI 僅 NT$278M（接近損平）但營運現金流強勁。2024 年因 NI 為負（-NT$530M），比值轉負無意義，但 CFO 仍達 NT$4.90B。2025 年 NI 回升至 NT$960M，比值 516%，依然遠高於製造業 100-120% 的健康基準。</li><li><strong>深度見解</strong>：CFO 超越 NI 的驅動力來自年化 NT$3.9-4.6B 的折舊費用，佔 CFO 的 79-108%。扣除折舊後，營運資金變動對 CFO 的貢獻有限：2023 年應收增 NT$232M、存貨增 NT$308M（資金佔用）；2025 年應收增 NT$374M（資金佔用）、應付增 NT$568M（資金挹注）。營運資金管理尚屬穩健，未有巨額異常膨脹。</li></ul><h3 id="自由現金流穿透-fcf-改善的內涵與風險" tabindex="-1">自由現金流穿透：FCF 改善的內涵與風險 <a class="header-anchor" href="#自由現金流穿透-fcf-改善的內涵與風險" aria-label="Permalink to &quot;自由現金流穿透：FCF 改善的內涵與風險&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FCF 從 2023 年 NT$1.52B 躍升至 2025 年 NT$10.07B。期間 CapEx 從 NT$3.11B 大幅縮減至 NT$0.70B（-77.5%），主因 2023 年為擴產高峰後進入資本節儉期。2024-2025 年投資活動現金流合計貢獻約 NT$4.06B（包含金融資產到期收回等項目）。</li><li><strong>深度見解</strong>：CapEx 縮減雖推升短期 FCF，但半導體產業需持續投資以維持製程競爭力。2025 年 CapEx 僅佔 CFO 的 14%，若未來 2-3 年未回升至 25-30%，可能壓抑長期營收成長動能。2025 年現金餘額 NT$7.07B，較 2023 年 NT$10.33B 減少 31.6%，主因償還長期借款 NT$7.99B。資產負債表已顯著去槓桿化。</li></ul><h3 id="結構性因素-折舊掩蓋下的真實獲利" tabindex="-1">結構性因素：折舊掩蓋下的真實獲利 <a class="header-anchor" href="#結構性因素-折舊掩蓋下的真實獲利" aria-label="Permalink to &quot;結構性因素：折舊掩蓋下的真實獲利&quot;">​</a></h3><ul><li><strong>核心重點</strong>：穩懋每年折舊 NT$3.9-4.6B，遠高於營業利益（2023 年營益 -NT$0.06B、2024 年 NT$0.77B、2025 年 NT$0.71B）。扣除折舊前的 EBITDA 估算為 NT$3.8-4.7B，才是反映本業現金產能的真實數字。</li><li><strong>深度見解</strong>：投資人若僅以 PE 評價穩懋將嚴重失真，因 NI 被折舊大幅壓縮。應以 EV/EBITDA 為主要估值工具。農牧部門連年虧損加劇 NI 失真程度。</li></ul><h2 id="💡-專家評析-387-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（387 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-387-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（387 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>CapEx 縮減潛藏長期競爭力風險</strong>：穩懋 CapEx 從 2023 年 NT$3.11B 驟降至 2025 年 NT$0.70B，資本支出強度從 19.6% 降至 4.2%。雖然短期推升 FCF 至 NT$10.07B 歷史高點，但 GaAs 晶圓代工產業製程迭代快速，競爭對手（如 GCS、Qorvo 自有產能）持續投資。若穩懋長期維持低 CapEx 策略，可能在 6/8 吋 GaAs 製程升級上落後，導致市佔率下滑壓力。</p></li><li><p><strong>2024 年 NI 轉負揭示獲利韌性不足</strong>：2024 年全年稅後淨利 -NT$530M，雖 CFO 仍強勁，但營益率僅 4.4%，顯示營運槓桿雙向作用顯著。當產能利用率下滑至 45%（2025 H1），營益即可能再次翻負。2023 年營益率 -0.4% 已證明此警訊。折舊覆蓋下的獲利防護層薄弱，NI 對產能利用率高度敏感。</p></li><li><p><strong>業外投資活動貢獻 FCF 的一次性疑慮</strong>：2025 年 FCF 高達 NT$10.07B，其中包含投資活動淨現金流入約 NT$5.11B（如金融資產處分、定期存款到期），非本業營運常態貢獻。若剔除該一次性項目，核心 FCF（CFO - CapEx）約為 NT$4.26B，僅為帳面 FCF 的 42%。投資者不宜以 2025 年 FCF 峰值作為常態預估基準。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (cashflow_quality 3105 2023 2025)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement、TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（現金流量表、負債資料）</li><li>查詢參數：stock_id=3105, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：CFO 2025=NT$4,952,971K, CapEx=NT$697,229K, Depreciation=NT$3,906,623K</li></ul>',19)])])}const c=t(r,[["render",e]]);export{h as __pageData,c as default};
